   119→    *crop_image;
   120→
   121→  PointInfo
   122→    extent[4],
   123→    min,
   124→    max;
   125→
   126→  RectangleInfo
   127→    geometry,
   128→    page;
   129→
   130→  register ssize_t
   131→    i;
   132→
   133→  /*
   134→    Calculate the rotated image size.
   135→  */
   136→  extent[0].x=(double) (-width/2.0);
   137→  extent[0].y=(double) (-height/2.0);
   138→  extent[1].x=(double) width/2.0;
   139→  extent[1].y=(double) (-height/2.0);
